--
-- Name: get_tank_capacity_by_depth_cm(integer, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_tank_capacity_by_depth_cm(p_tank_id integer, p_depth_cm numeric) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    depth_cm_trimmed numeric := TRUNC(p_depth_cm, 1);          -- ne garder qu'une d‚cimale
    depth_mm integer := (depth_cm_trimmed * 10)::integer;      -- conversion en mm
    v_min_depth integer;
    v_max_depth integer;
    exact_volume numeric;
    low_d integer; low_v numeric;
    high_d integer; high_v numeric;
    decimal_digit integer;
    frac numeric;
    interp_volume numeric;
BEGIN
    SELECT MIN(depth), MAX(depth)
    INTO v_min_depth, v_max_depth
    FROM tank_chart_point
    WHERE tank_id = p_tank_id;

    IF v_min_depth IS NULL OR v_max_depth IS NULL THEN
        RETURN 'Charte vide';
    END IF;

    IF depth_mm = 0 THEN
        RETURN 'Aucun volume mesurable';
    ELSIF depth_mm < v_min_depth OR depth_mm > v_max_depth THEN
        RETURN 'Volume non pris en charge';
    END IF;

    -- cas exact
    SELECT volume INTO exact_volume
    FROM tank_chart_point
    WHERE tank_id = p_tank_id AND depth = depth_mm AND volume IS NOT NULL
    LIMIT 1;

    IF exact_volume IS NOT NULL THEN
        RETURN ROUND(exact_volume)::integer::text; -- arrondi standard
    END IF;

    -- point inf‚rieur
    SELECT depth, volume INTO low_d, low_v
    FROM tank_chart_point
    WHERE tank_id = p_tank_id AND depth < depth_mm AND volume IS NOT NULL
    ORDER BY depth DESC
    LIMIT 1;

    -- point sup‚rieur
    SELECT depth, volume INTO high_d, high_v
    FROM tank_chart_point
    WHERE tank_id = p_tank_id AND depth > depth_mm AND volume IS NOT NULL
    ORDER BY depth ASC
    LIMIT 1;

    IF low_d IS NULL OR high_d IS NULL THEN
        RETURN 'Volume non pris en charge';
    END IF;

    IF high_d = low_d THEN
        RETURN 'Volume non pris en charge';
    END IF;

    -- EXTRAIRE LE PREMIER CHIFFRE APRES LA VIRGULE
    decimal_digit := ((depth_cm_trimmed * 10)::integer % 10);
    IF decimal_digit < 0 THEN decimal_digit := ABS(decimal_digit); END IF;

    frac := decimal_digit::numeric / 10.0;

    -- interpolation selon ta rŠgle m‚tier
    interp_volume := low_v + frac * (high_v - low_v);

    IF interp_volume IS NULL THEN
        RETURN 'Volume non pris en charge';
    END IF;

    RETURN ROUND(interp_volume)::integer::text;
END;
$$;


ALTER FUNCTION public.get_tank_capacity_by_depth_cm(p_tank_id integer, p_depth_cm numeric) OWNER TO postgres;

--
-- Name: tank_get_height_for_volume(integer, numeric); Type: FUNCTION; Schema: public; Owner: tank_user
--

CREATE FUNCTION public.tank_get_height_for_volume(tank_id_param integer, v_val_param numeric) RETURNS numeric
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  p_lo RECORD;
  p_hi RECORD;
  result NUMERIC;
BEGIN
  IF tank_id_param IS NULL OR v_val_param IS NULL THEN
    RETURN NULL;
  END IF;

  SELECT * INTO p_lo
  FROM tank_chart_point
  WHERE tank_id = tank_id_param AND volume <= v_val_param
  ORDER BY volume DESC
  LIMIT 1;

  SELECT * INTO p_hi
  FROM tank_chart_point
  WHERE tank_id = tank_id_param AND volume >= v_val_param
  ORDER BY volume ASC
  LIMIT 1;

  IF p_lo IS NOT NULL AND p_lo.volume = v_val_param THEN
    RETURN p_lo.height;
  ELSIF p_hi IS NOT NULL AND p_hi.volume = v_val_param THEN
    RETURN p_hi.height;
  END IF;

  IF p_lo IS NOT NULL AND p_hi IS NOT NULL THEN
    IF p_hi.volume = p_lo.volume THEN
      RETURN p_lo.height;
    END IF;
    result := p_lo.height + ((v_val_param - p_lo.volume) * (p_hi.height - p_lo.height)) / (p_hi.volume - p_lo.volume);
    RETURN result;
  END IF;

  IF p_lo IS NULL AND p_hi IS NOT NULL THEN
    RETURN p_hi.height;
  ELSIF p_hi IS NULL AND p_lo IS NOT NULL THEN
    RETURN p_lo.height;
  END IF;

  RETURN NULL;
END;
$$;


ALTER FUNCTION public.tank_get_height_for_volume(tank_id_param integer, v_val_param numeric) OWNER TO tank_user;

