--
-- Name: tank_status; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.tank_status AS
 SELECT t.id,
    t.name,
    t.capacity,
    m.calculated_volume_liters AS current_volume,
    round((((m.calculated_volume_liters)::numeric / (NULLIF(t.capacity, 0))::numeric) * (100)::numeric), 1) AS fill_percent,
    m.measured_at AS last_measured_at
   FROM (public.tanks t
     LEFT JOIN LATERAL ( SELECT measurements.calculated_volume_liters,
            measurements.measured_at
           FROM public.measurements
          WHERE (measurements.tank_id = t.id)
          ORDER BY measurements.measured_at DESC
         LIMIT 1) m ON (true));


ALTER VIEW public.tank_status OWNER TO postgres;

